import { test, expect, Page } from '@playwright/test';

// Helper function to wait for a todo to be created
async function waitForTodoCountToIncrease(page: Page, initialCount: number) {
  await page.waitForFunction(
    (count) => {
      const items = document.querySelectorAll('[role="checkbox"]');
      return items.length > count;
    },
    initialCount,
    { timeout: 10000 }
  );
}

